Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
pull.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function pull (a) {
  var length = arguments.length
  if (typeof a === 'function' && a.length === 1) {
    var args = new Array(length)
    for(var i = 0; i < length; i++)
      args[i] = arguments[i]
    return function (read) {
      if (args == null) {
        throw new TypeError("partial sink should only be called once!")
      }

      // Grab the reference after the check, because it's always an array now
      // (engines like that kind of consistency).
      var ref = args
      args = null

      // Prioritize common case of small number of pulls.
      switch (length) {
      case 1: return pull(read, ref[0])
      case 2: return pull(read, ref[0], ref[1])
      case 3: return pull(read, ref[0], ref[1], ref[2])
      case 4: return pull(read, ref[0], ref[1], ref[2], ref[3])
      default:
        ref.unshift(read)
        return pull.apply(null, ref)
      }
    }
  }

  var read = a

  if (read && typeof read.source === 'function') {
    read = read.source
  }

  for (var i = 1; i < length; i++) {
    var s = arguments[i]
    if (typeof s === 'function') {
      read = s(read)
       <PLACEHOLDER>

      s.sink(read)
      read = s.source
    }
  }

  return read
}

In the original code, <PLACEHOLDER> has the value:

-       } else if (s && typeof s === 'object') {
In the mutated code, <PLACEHOLDER> has the value:

+       } else if (s && true) {


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-d557c4c/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the original code checks `} else if (s && typeof s === 'object') {` but the mutated code changes it to `} else if (s && true) {`.

This means in the mutated version, when `s` is a function (not an object), the `else if` branch will also execute after `read = s(read)`, trying to call `s.sink(read)` and `read = s.source`. This would cause issues when `s` is a plain function (through-stream as function) because functions don't have `.sink` and `.source` properties in the same way objects do.

Let me think about what scenario would expose this:
- When `s` is a function (a through-stream as function), the original code only does `read = s(read)` and skips the `else if` branch
- In the mutated code, after `read = s(read)`, it would also try to execute `s.sink(read)` and `read = s.source`

If `s` is a plain function without `.sink` and `.source`, then:
- `s.sink` would be `undefined`, calling `undefined(read)` would throw a TypeError
- OR `read = s.source` would set `read` to `undefined`

Let me write a test that uses a through-stream as a plain function (no `.sink`/`.source`), which should work fine in the original but fail in the mutated version.

```typescript
import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with function through-stream", () => {
  it("should correctly pipe through a function-based through-stream without treating it as an object", (done) => {
    // Create a simple source that emits values 1, 2, 3 then ends
    function source(end: any, cb: Function) {
      if (end) return cb(end)
      let i = 0
      const values = [1, 2, 3]
      return function(end: any, cb: Function) {
        if (end || i >= values.length) return cb(true)
        cb(null, values[i++])
      }
    }

    // Create a through-stream as a plain function (no .sink or .source properties)
    function double(read: Function) {
      return function(end: any, cb: Function) {
        read(end, function(end: any, data: any) {
          if (end) return cb(end)
          cb(null, data * 2)
        })
      }
    }

    // Create a sink that collects results
    const results: number[] = []
    function sink(read: Function) {
      function next() {
        read(null, function(end: any, data: any) {
          if (end) {
            expect(results).toEqual([2, 4, 6])
            done()
            return
          }
          results.push(data)
          next()
        })
      }
      next()
    }

    // In the original, double is a function so only read = s(read) is called
    // In the mutated version, it would also try s.sink(read) which would throw
    // since double.sink is undefined
    pull(source(null, () => {}), double, sink)
  })
})
